def incassi_settimana():
    db = get_db()
    # Calcola la data di 7 giorni fa rispetto a oggi (incluso)
    # SQLite date('now', '-6 days') restituisce la data di 6 giorni fa.
    # Per avere "gli ultimi 7 giorni" inclusi oggi, usiamo >= data di 6 giorni fa.
    row = db.execute(
        'SELECT SUM(totale_cents) as total FROM transazioni WHERE data >= date("now", "-6 days")'
    ).fetchone()

    incasso = row['total'] if row['total'] is not None else 0

    return jsonify({"incasso_cents": incasso})
