from flask import Flask, jsonify
import sqlite3
from datetime import datetime, timedelta

app = Flask(__name__)

def get_db():
    return sqlite3.connect('database.db')

@app.route('/api/incassi/settimana')
def incassi_settimana():
    db = get_db()
    cursor = db.cursor()
    week_ago = (datetime.now() - timedelta(days=7)).strftime('%Y-%m-%d')
    cursor.execute("SELECT SUM(totale_cents) FROM transazioni WHERE data >= ?", (week_ago,))
    result = cursor.fetchone()
    incasso_cents = result[0] if result[0] else 0
    db.close()
    return jsonify({"incasso_cents": incasso_cents})

if __name__ == '__main__':
    app.run()
